+\begin{lemma}
+[Projectivity descends to scheme-theoretic fibres]
+  \label{lem:projective_with_fiber}
+  \leanok
+  \lean{AlgebraicGeometry.Scheme.Hom.IsProjectiveWith.fiber}
+  \uses{def:projective_with, lem:projective_with_base_change}
+  Let \(\pi : X \to S\) be projective carrying \(L\) and let \(s \in S\).  Then
+  the structural morphism of the scheme-theoretic fibre
+  \(X_s = X \times_S \operatorname{Spec}\kappa(s)\), namely
+  \(X_s \to \operatorname{Spec}\kappa(s)\), is projective carrying the
+  restriction \(L_s = L|_{X_s}\).
+\end{lemma}
+
+\begin{proof}
+  \leanok
+  \uses{lem:projective_with_base_change}
+  The fibre \(X_s\) is the base change of \(\pi\) along the canonical morphism
+  \(\operatorname{Spec}\kappa(s) \to S\), and \(X_s \to
+  \operatorname{Spec}\kappa(s)\) is the second projection.  Apply
+  \Cref{lem:projective_with_base_change} to that morphism: the base change is
+  projective carrying the pullback of \(L\) along the fibre embedding
+  \(X_s \to X\), which is exactly \(L_s\).
+\end{proof}
+
+\begin{lemma}
+[Finite presentation descends to fibres]
+  \label{lem:fiberModule_finitePresentation}
+  \leanok
+  \lean{AlgebraicGeometry.Scheme.Hom.fiberModule_isFinitePresentation}
+  \uses{def:fiber_module_restriction}
+  If \(F\) is a finitely presented sheaf of modules on \(X\), then its
+  restriction \(F_s = F|_{X_s}\) to the fibre over \(s \in S\)
+  (\Cref{def:fiber_module_restriction}) is finitely presented.
+\end{lemma}
+
+\begin{proof}
+  \leanok
+  \(F_s\) is the pullback of \(F\) along the fibre embedding \(X_s \to X\), and
+  finite presentation of a sheaf of modules is stable under pullback along an
+  arbitrary morphism of schemes.
+\end{proof}
+
+\begin{lemma}
+[Serre finiteness along a fibre]
+  \label{lem:sectionGradedModule_fg_fiber}
+  \leanok
+  \lean{AlgebraicGeometry.sectionGradedModule_fg_fiber}
+  \uses{lem:sectionGradedModule_fg, lem:projective_with_fiber,
+    lem:fiberModule_finitePresentation, def:sectionGradedRing,
+    def:sectionGradedModule}
+  Let \(\pi : X \to S\) be projective carrying \(L\), let \(F\) be finitely
+  presented, and let \(s \in S\).  Then the section graded ring \(R(X_s, L_s)\)
+  (\Cref{def:sectionGradedRing}) is Noetherian and the section graded module
+  \(M(X_s, F_s, L_s)\) (\Cref{def:sectionGradedModule}) is a finitely generated
+  \(R(X_s, L_s)\)-module.
+\end{lemma}
+
+\begin{proof}
+  \uses{lem:sectionGradedModule_fg, lem:projective_with_fiber,
+    lem:fiberModule_finitePresentation}
+  The fibre \(X_s\) is projective over the field \(\kappa(s)\) carrying \(L_s\)
+  (\Cref{lem:projective_with_fiber}), and \(F_s\) is coherent
+  (\Cref{lem:fiberModule_finitePresentation}); apply
+  \Cref{lem:sectionGradedModule_fg} on \(X_s\), retaining its first two
+  conclusions.
+\end{proof}
+
+\begin{lemma}
+[The graded Hilbert function is a genuine dimension on projective fibres]
+  \label{lem:hilbertFunction_finiteDimensional}
+  \leanok
+  \lean{AlgebraicGeometry.hilbertFunction_finiteDimensional}
+  \uses{lem:sectionGradedModule_fg, lem:projective_with_fiber,
+    lem:fiberModule_finitePresentation, def:hilbert_polynomial}
+  Let \(\pi : X \to S\) be projective carrying \(L\), let \(F\) be finitely
+  presented, and let \(s \in S\).  Then for every \(m\) the space of global
+  sections \(\Gamma(X_s, F_s \otimes L_s^{\otimes m})\) is a finite-dimensional
+  \(\kappa(s)\)-vector space.  In particular the graded Hilbert function
+  \(m \mapsto \dim_{\kappa(s)} \Gamma(X_s, F_s \otimes L_s^{\otimes m})\)
+  (\Cref{def:hilbert_polynomial}) takes finite values, so it is not the
+  \(\operatorname{finrank}\) junk value at any \(m\).
+\end{lemma}
+
+\begin{proof}
+  \uses{lem:sectionGradedModule_fg, lem:projective_with_fiber,
+    lem:fiberModule_finitePresentation}
+  This is the third conclusion of \Cref{lem:sectionGradedModule_fg} applied on
+  the fibre \(X_s\), which is projective over \(\kappa(s)\) carrying \(L_s\)
+  (\Cref{lem:projective_with_fiber}) with \(F_s\) coherent
+  (\Cref{lem:fiberModule_finitePresentation}): finite dimensionality over the
+  residue field of each graded component
+  \(\Gamma(X_s, F_s \otimes L_s^{\otimes m})\).
+\end{proof}
+
